import React, { useEffect, useState } from 'react';
import { supabase } from '../services/supabaseClient';
import { PiggyBank, AlertCircle, ArrowUpCircle, ArrowDownCircle, Target, CreditCard, Calendar } from 'lucide-react';
import '../styles/Orcamento.css';

const Orcamento = () => {
  const [loading, setLoading] = useState(true);
  const [dados, setDados] = useState({
    metaGlobal: 0,
    gastoTotal: 0,
    receitaTotal: 0,
    gastoCartao: 0,
    gastoVariavel: 0,
    categorias: []
  });

  useEffect(() => {
    buscarDadosReais();
  }, []);

  async function buscarDadosReais() {
    setLoading(true);
    try {
      const agora = new Date();
      const ano = agora.getFullYear();
      const mes = agora.getMonth() + 1;
      const primeiroDia = `${ano}-${String(mes).padStart(2, '0')}-01`;
      const ultimoDia = new Date(ano, mes, 0).toISOString().split('T')[0];

      // 1. Buscar Proventos do mês
      const { data: proventos } = await supabase
        .from('proventos')
        .select('valor')
        .gte('data_recebimento', primeiroDia)
        .lte('data_recebimento', ultimoDia);

      const totalProventos = proventos?.reduce((acc, cur) => acc + Number(cur.valor), 0) || 0;

      // 2. Buscar Compras do Mês (Para pegar Variáveis E Crédito 1x)
      const { data: comprasMes } = await supabase
        .from('compras')
        .select('valor_total, categoria_id, tipo_despesa, num_parcelas')
        .gte('data_compra', primeiroDia)
        .lte('data_compra', ultimoDia);

      // 3. Buscar Parcelas que vencem este mês (Para compras parceladas antigas ou novas)
      const { data: parcelasMes } = await supabase
        .from('parcelas')
        .select(`
          valor_parcela,
          compra:compra_id (
            categoria_id,
            tipo_despesa
          )
        `)
        .gte('data_vencimento', primeiroDia)
        .lte('data_vencimento', ultimoDia);

      // --- Lógica de Separação de Gastos ---

      // Gastos Variáveis (Pix/Débito)
      const totalVariavel = comprasMes
        ?.filter(c => c.tipo_despesa === 'Gastos Variáveis')
        .reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;

      // Crédito à Vista (1x) - Compras feitas este mês no crédito que não são parceladas
      const totalCreditoAVista = comprasMes
        ?.filter(c => c.tipo_despesa === 'Compra no Crédito' && (Number(c.num_parcelas) <= 1 || !c.num_parcelas))
        .reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;

      // Crédito Parcelado (Parcelas que vencem hoje, independente de quando a compra foi feita)
      const totalParceladoMes = parcelasMes?.reduce((acc, cur) => acc + Number(cur.valor_parcela), 0) || 0;

      const totalCartaoFatura = totalCreditoAVista + totalParceladoMes;
      const gastoTotalGeral = totalVariavel + totalCartaoFatura;

      // 4. Buscar Categorias e Consolidar
      const { data: cats } = await supabase.from('categorias').select('*').order('nome', { ascending: true });

      const categoriasComSoma = cats.map(cat => {
        // Soma Variáveis da categoria
        const sv = comprasMes
          ?.filter(c => c.categoria_id === cat.id && c.tipo_despesa === 'Gastos Variáveis')
          .reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;

        // Soma Crédito à Vista da categoria
        const scav = comprasMes
          ?.filter(c => c.categoria_id === cat.id && c.tipo_despesa === 'Compra no Crédito' && (Number(c.num_parcelas) <= 1 || !c.num_parcelas))
          .reduce((acc, cur) => acc + Number(cur.valor_total), 0) || 0;

        // Soma Parcelas da categoria
        const sp = parcelasMes
          ?.filter(p => p.compra?.categoria_id === cat.id)
          .reduce((acc, cur) => acc + Number(cur.valor_parcela), 0) || 0;

        return { 
          ...cat, 
          gastoReal: sv + scav + sp,
          meta: cat.meta_categoria || 0 
        };
      });

      const somaMetas = categoriasComSoma
        .filter(c => c.tipo === 'despesa')
        .reduce((acc, cur) => acc + (Number(cur.meta) || 0), 0);

      setDados({
        metaGlobal: somaMetas > 0 ? somaMetas : totalProventos,
        gastoTotal: gastoTotalGeral,
        receitaTotal: totalProventos,
        gastoCartao: totalCartaoFatura,
        gastoVariavel: totalVariavel,
        categorias: categoriasComSoma
      });

    } catch (err) {
      console.error("Erro ao processar indicadores:", err);
    } finally {
      setLoading(false);
    }
  }

  const formatMoney = (v) => v.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
  const porcGlobal = (dados.gastoTotal / dados.metaGlobal) * 100;
  const mesAtualNome = new Intl.DateTimeFormat('pt-BR', { month: 'long' }).format(new Date());

  if (loading) return <div className="loading-state">Consolidando gastos de {mesAtualNome}...</div>;

  return (
    <div className="orcamento-container fade-in">
      <header className="orcamento-header">
        <div>
           <h2>Painel de Orçamento</h2>
           <p className="mes-referencia">
             <Calendar size={14} style={{verticalAlign: 'middle', marginRight: '5px'}} />
             Fatura de: <strong>{mesAtualNome.charAt(0).toUpperCase() + mesAtualNome.slice(1)}</strong>
           </p>
        </div>
        <button className="btn-ajuste" onClick={() => window.location.href='/categorias'}>
          <Target size={18} /> Configurar Metas
        </button>
      </header>

      {/* CARD GLOBAL */}
      <section className="meta-global-card">
        <div className="meta-info">
          <div className="meta-text">
            <span className="label">Fluxo de Caixa Mensal</span>
            <h3>{formatMoney(dados.gastoTotal)} <small>/ {formatMoney(dados.metaGlobal)}</small></h3>
          </div>
          <PiggyBank size={40} className="icon-main" style={{color: '#4361ee'}} />
        </div>
        <div className="progress-bar-container">
          <div 
            className={`progress-bar-fill ${porcGlobal > 100 ? 'over-limit' : ''}`} 
            style={{ width: `${Math.min(porcGlobal, 100)}%` }} 
          />
        </div>
        <div className="meta-footer">
          <span className="progress-label">{porcGlobal.toFixed(1)}% do orçamento</span>
          <span className="remaining-label">
            {dados.gastoTotal > dados.metaGlobal 
              ? `Excedido em ${formatMoney(dados.gastoTotal - dados.metaGlobal)}`
              : `Disponível: ${formatMoney(dados.metaGlobal - dados.gastoTotal)}`
            }
          </span>
        </div>
      </section>

      <div className="two-columns-grid">
        <section className="orc-section">
          <h3 className="section-title"><ArrowUpCircle size={18} color="#10b981" /> Entradas</h3>
          <div className="summary-box proventos-bg">
            <span className="label">Receita do Mês</span>
            <p className="value">{formatMoney(dados.receitaTotal)}</p>
          </div>
        </section>

        <section className="orc-section">
          <h3 className="section-title"><CreditCard size={18} color="#ef4444" /> Saídas (Fatura + Pix)</h3>
          <div className="summary-box despesas-bg">
            <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center'}}>
              <div>
                <span className="label">Total Cartão</span>
                <p className="value" style={{fontSize: '1.2rem'}}>{formatMoney(dados.gastoCartao)}</p>
              </div>
              <div style={{textAlign: 'right'}}>
                <span className="label">À Vista</span>
                <p className="value" style={{fontSize: '1.2rem'}}>{formatMoney(dados.gastoVariavel)}</p>
              </div>
            </div>
          </div>
        </section>
      </div>

      <h3 className="section-title" style={{marginTop: '30px'}}>Detalhamento por Categoria</h3>
      <div className="orcamento-grid">
        {dados.categorias.filter(c => c.tipo === 'despesa').map((cat) => {
          const porc = cat.meta > 0 ? (cat.gastoReal / cat.meta) * 100 : 0;
          const excedeu = cat.gastoReal > cat.meta && cat.meta > 0;

          return (
            <div key={cat.id} className={`categoria-card ${excedeu ? 'card-excedido' : ''}`}>
              <div className="categoria-header">
                <div className="cat-info-main">
                  <div className="dot" style={{backgroundColor: cat.cor}}></div>
                  <span className="cat-nome">{cat.nome}</span>
                </div>
                {excedeu && <AlertCircle size={16} color="#ef4444" />}
              </div>
              <div className="cat-body">
                <div className="categoria-valores">
                  <div className="v-group">
                    <label>Gasto Real</label>
                    <span className="valor-gasto">{formatMoney(cat.gastoReal)}</span>
                  </div>
                  <div className="v-group align-right">
                    <label>Meta</label>
                    <span className="valor-meta">{formatMoney(cat.meta)}</span>
                  </div>
                </div>
                <div className="mini-progress-bg">
                  <div 
                    className="mini-progress-fill" 
                    style={{ 
                      width: `${Math.min(porc, 100)}%`, 
                      backgroundColor: excedeu ? '#ef4444' : cat.cor 
                    }} 
                  />
                </div>
                <span className="porc-individual">{porc.toFixed(0)}% consumido</span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default Orcamento;
